 86	void compute_nr_prach_seq(uint8_t short_sequence, uint8_t num_sequences, uint8_t rootSequenceIndex, c16_t X_u[64][839])
 87	{
 88	  // Compute DFT of x_u => X_u[k] = x_u(inv(u)*k)^* X_u[k] = exp(j\pi u*inv(u)*k*(inv(u)*k+1)/N_ZC)
 89	  int N_ZC;
 90	
 91	  const uint16_t* prach_root_sequence_map;
 92	
 93	  VCD_SIGNAL_DUMPER_DUMP_FUNCTION_BY_NAME(VCD_SIGNAL_DUMPER_FUNCTIONS_PHY_UE_COMPUTE_PRACH, VCD_FUNCTION_IN);
 94	
 95	  LOG_D(PHY,"compute_prach_seq: prach short sequence %x, num_sequences %d, rootSequenceIndex %d\n", short_sequence, num_sequences, rootSequenceIndex);
 96	
 97	  N_ZC = (short_sequence) ? NR_PRACH_SEQ_LEN_S : NR_PRACH_SEQ_LEN_L;
 98	
 99	  if (short_sequence) {
100	    // FIXME cannot be reached
101	    prach_root_sequence_map = prach_root_sequence_map_abc;
102	  } else {
103	    prach_root_sequence_map = prach_root_sequence_map_0_3;
104	  }
105	
106	  LOG_D( PHY, "compute_prach_seq: done init prach_tables\n" );
107	
108	  for (int i = 0; i < num_sequences; i++) {
109	    int index = (rootSequenceIndex+i) % (N_ZC-1);
110	
111	    if (short_sequence) {
112	      // prach_root_sequence_map points to prach_root_sequence_map4
113	      DevAssert( index < sizeof(prach_root_sequence_map_abc) / sizeof(prach_root_sequence_map_abc[0]) );
114	    } else {
115	      // prach_root_sequence_map points to prach_root_sequence_map0_3
116	      DevAssert( index < sizeof(prach_root_sequence_map_0_3) / sizeof(prach_root_sequence_map_0_3[0]) );
117	    }
118	
119	    const uint16_t u = prach_root_sequence_map[index];
120	    LOG_D(PHY,"prach index %d => u=%d\n",index,u);
121	    const int inv_u = modulo_multiplicative_inverse(u, N_ZC); // multiplicative inverse of u
122	
123	    // X_u[0] stores the first ZC sequence where the root u has a non-zero number of shifts
124	    // for the unrestricted case X_u[0] is the first root indicated by the rootSequenceIndex
125	
126	    const int zc_inv_2 = modulo_multiplicative_inverse(2, N_ZC);
127	    for (int k = 0; k < N_ZC; k++) {
128	      const unsigned int j = (((k * (1 + (inv_u * k))) % N_ZC) * zc_inv_2) % N_ZC;
129	      const double w = 2 * M_PI * (double)j / N_ZC;
130	      const c16_t ru = {.r = (int16_t)(floor(32767.0 * cos(w))), .i = (int16_t)(floor(32767.0 * sin(w)))};
131	      // multiply by inverse of 2 (required since ru is exp[j 2\pi n])
132	      X_u[i][k] = ru;
133	    }
134	  }
135	
136	  VCD_SIGNAL_DUMPER_DUMP_FUNCTION_BY_NAME(VCD_SIGNAL_DUMPER_FUNCTIONS_PHY_UE_COMPUTE_PRACH, VCD_FUNCTION_OUT);
137	}

